// Витягуємо контекст з callback_data формату "lead_context_external_id"
if (originalCallback.startsWith('lead_')) {
    const parts = originalCallback.split('_');
    if (parts.length >= 3) {
        context = parts.slice(1, -1).join('_');
    }
} else if (originalCallback.startsWith('take_')) {
    const parts = originalCallback.split('_');
    if (parts.length >= 3) {
        context = parts.slice(1, -1).join('_');
    }
} else if (originalCallback.startsWith('disable_')) {
    const parts = originalCallback.split('_');
    if (parts.length >= 3) {
        context = parts.slice(1, -1).join('_');
    }
} else if (originalCallback.startsWith('finish_')) {
    const parts = originalCallback.split('_');
    if (parts.length >= 3) {
        context = parts.slice(1, -1).join('_');
    }
} else if (originalCallback.startsWith('enable_')) {
    const parts = originalCallback.split('_');
    if (parts.length >= 3) {
        context = parts.slice(1, -1).join('_');
    }
}

const messageId = originalData.callback_query.message.message_id;
const chatId = originalData.callback_query.message.chat.id;

if (!lead || !lead.external_id) {
    return {
        chat_id: chatId,
        message_id: messageId,
        text: '❌ <b>Помилка</b>\n\nЛіда не знайдено',
        reply_markup: {
            inline_keyboard: [
                [{ text: '⬅️ Назад до списку', callback_data: `page_${context}_0` }],
                [{ text: '❌ Закрити список', callback_data: 'close' }]
            ]
        },
        parse_mode: 'HTML'
    };
}

let firstName = '';
let username = '';

if (lead.first_name && String(lead.first_name) !== 'undefined' && String(lead.first_name) !== 'null' && String(lead.first_name).trim() !== '') {
    firstName = String(lead.first_name).trim();
}

if (lead.username && String(lead.username) !== 'undefined' && String(lead.username) !== 'null' && String(lead.username).trim() !== '') {
    username = String(lead.username).trim();
}

let displayName = '';
if (firstName) {
    displayName = firstName;
} else if (username) {
