if (lead.agent_disable_type === 'manual') {
    agentStatus = '🔴 Відключений вручну';
} else if (lead.agent_disable_type === 'temporary') {
    agentStatus = '🟡 Тимчасово відключений';
} else if (lead.agent_disabled) {
    agentStatus = '🔴 Відключений';
} else {
    agentStatus = '🟢 Активний';
}

let communicationStatus = '';
if (lead.operator_connected && lead.connected_operator_name) {
    communicationStatus = `👨‍💻 Спілкується з оператором ${lead.connected_operator_name}`;
