} else if (lead.agent_disabled) {
    communicationStatus = '🚫 Агент відключений';
} else {
    communicationStatus = '💬 Спілкується з ботом';
}

let callReason = '';
if (lead.last_message_from) {
    switch (lead.last_message_from) {
        case 'purchase_ready':
            callReason = '💰 Готовий до покупки';
            break;
