const allItems = $input.all();
const leads = allItems.map(item => item.json);

const hasRealData = leads.length > 0 && leads[0] && leads[0].external_id;
const callbackData = $('Code').first().json.callback_query?.data || '';

const context = 'agent_active';
let currentPage = 0;

if (callbackData === 'refresh_agent_active') {
    currentPage = 0;
} else if (callbackData.startsWith('page_agent_active_')) {
    currentPage = parseInt(callbackData.split('_').pop()) || 0;
}

const totalCount = hasRealData ? (leads[0].total_count || 0) : 0;
const totalPages = Math.ceil(totalCount / 10);

function formatActivityTime(dateString) {
    if (!dateString) return '';

    const activityDate = new Date(dateString);
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const yesterday = new Date(today.getTime() - 24 * 60 * 60 * 1000);
    const activityDay = new Date(activityDate.getFullYear(), activityDate.getMonth(), activityDate.getDate());

    const timeString = activityDate.toLocaleTimeString('uk-UA', { hour: '2-digit', minute: '2-digit' });

    if (activityDay.getTime() === today.getTime()) {
        return `🕐 ${timeString}`;
    } else if (activityDay.getTime() === yesterday.getTime()) {
        return `📅 Вчора ${timeString}`;
    } else {
        const dateString = activityDate.toLocaleDateString('uk-UA', { day: '2-digit', month: '2-digit' });
        return `📅 ${dateString} ${timeString}`;
    }
}

let keyboard = [];

if (hasRealData && totalCount > 0) {
    leads.forEach((lead, index) => {
        try {
            if (!lead || !lead.external_id) return;

            let firstName = '';
            let username = '';

            if (lead.first_name && 
                String(lead.first_name) !== 'undefined' && 
                String(lead.first_name) !== 'null' && 
                String(lead.first_name).trim() !== '') {
                firstName = String(lead.first_name).trim();
            }

            if (lead.username && 
                String(lead.username) !== 'undefined' && 
                String(lead.username) !== 'null' && 
                String(lead.username).trim() !== '') {
                username = String(lead.username).trim();
            }

            let activityTime = formatActivityTime(lead.last_activity_at);
            let displayName = '';
            if (firstName) {
                displayName = firstName;
            } else if (username) {
                displayName = username;
            } else {
                if (lead.channel_type === 'facebook') {
                    displayName = activityTime || `ID: ${String(lead.external_id).slice(-6)}`;
                } else {
                    displayName = `ID: ${String(lead.external_id).slice(-6)}`;
                }
            }

            let channelName = '';
            if (lead.channel_type === 'facebook') {
                channelName = displayName ? `Фейсбук - ${displayName}` : 'Фейсбук';
            } else if (lead.channel_type === 'instagram') {
                channelName = displayName ? `Інстаграм - ${displayName}` : 'Інстаграм';
            } else {
                channelName = displayName ? `Чат - ${displayName}` : 'Чат';
            }

            if (activityTime && !(lead.channel_type === 'facebook' && !firstName && !username)) {
                channelName += `\n${activityTime}`;
            }

            const buttonData = {
                text: channelName,
                callback_data: `lead_${context}_${lead.external_id}`
            };

            keyboard.push([buttonData]);

        } catch (error) {
            console.error(`Error processing lead ${index}:`, error);
        }
    });
}

