        navigationRow.push({
            text: '⬅️ Назад',
            callback_data: `page_agent_active_${currentPage - 1}`
        });
    }
    if (currentPage < totalPages - 1) {
        navigationRow.push({
            text: 'Далі ➡️',
            callback_data: `page_agent_active_${currentPage + 1}`
