    callback_data: 'close'
}]);

const updateTime = new Date().toLocaleString('uk-UA', {
    timeZone: 'Europe/Kiev'
});

let messageText = '';

if (!hasRealData || totalCount === 0) {
    messageText = `🤖 <b>З ким спілкується агент зараз</b>\n\n`;
    messageText += `❌ <b>Немає активних клієнтів</b>\n\n`;
    messageText += `За останні 2 години жоден клієнт не спілкувався з агентом.\n`;
    messageText += `🔄 Оновлено: ${updateTime}`;
} else {
    const fromLead = currentPage * 10 + 1;
    const toLead = Math.min((currentPage + 1) * 10, totalCount);

    messageText = `🤖 <b>З ким спілкується агент зараз</b>\n\n`;
    messageText += `Сторінка: ${currentPage + 1} з ${totalPages}\n`;
    messageText += `Ліди: ${fromLead}-${toLead} з ${totalCount}\n`;
    messageText += `🔄 Оновлено: ${updateTime}`;
}

return {
    text: messageText,
    reply_markup: {
        inline_keyboard: keyboard
    },
    parse_mode: 'HTML'
};

